There are several kinds of comparisons we can make for both categorical and numeric data.


::: {.cell}

```{.r .cell-code}
avg_comparisons(
  um_model,
  variables = list(
    # comparison to a reference level
    gender = "reference",

    # pairwise comparison of all levels
    fol_class = "pairwise",

    # effect of adding +20 to dob
    dob = 20,

    # comparing two specific reference values
    relative_rate = c(2/1, 1/2),

    # comparing the 3rd and 1st quartile
    total_rate = "iqr"
  ),
  type = "link"
) ->
 all_comp
