      let style = get-style(x, y)
      if style != none and "background" in style { style.background }
    },
 table.hline(y: 1, start: 0, end: 6, stroke: 0.05em + black),
 table.hline(y: 3, start: 0, end: 6, stroke: 0.08em + black),
 table.hline(y: 0, start: 0, end: 6, stroke: 0.08em + black),
    // tinytable lines before

    // tinytable header start
    table.header(
      repeat: true,
[term], [contrast], [gender], [estimate], [conf.low], [conf.high],
    ),
    // tinytable header end

    // tinytable cell content after
[dob], [dY/dX], [man], [0.0763], [0.061], [0.0916],
[dob], [dY/dX], [woman], [0.0593], [0.0466], [0.0718],

    // tinytable footer after

  ) // end table

  ]) // end align

] // end block
```

:::
:::


The estimated slope for men is slightly steeper than for women.
Another way to explore this is to look at how much the difference between men and women has changed over dob.


::: {.cell}

```{.r .cell-code}
avg_slopes(
  um_model,
  variables = "gender",
  by = "dob",
  newdata = dob_gender_grid,
  type = "link",
  re_formula = NA
) ->
 gender_by_dob
```
:::



::: {.cell}

```{.r .cell-code  code-fold="true" code-summary="Plotting code."}
gender_by_dob |>
 ggplot(
   aes(dob, estimate)
 ) +
 geom_hline(
   yintercept = 0,
   linewidth = 0.5
 ) +
 geom_lineribbon(
   aes(ymin = conf.low, ymax = conf.high),
   alpha = 0.8
 )
```

::: {.cell-output-display}
![Estimated gender effect over DOB
](index_files/figure-typst/fig-gender-slope-1.svg){#fig-gender-slope}
:::
:::


::: {.callout-note collapse="true"}
## Aside

It's not straightforward from looking at just the estimated slopes by gender in @tbl-slope1 to tell whether the slopes are reliably different.
However, because we fit the model with brms, we can extract the posterior draws from the marginal effects object, and carry out some additional estimation.


::: {.cell}

```{.r .cell-code}
dob_by_gender |> 
 posterior_draws() |>
 arrange(gender) |>
 summarise(
   .by = drawid,
   interaction = diff(draw)
 ) |>
 mean_hdci(interaction) |> 
 tt()
```

